Here is the JWT HS256 verification implementation:

```typescript
import { createHmac, timingSafeEqual } from 'node:crypto';

export interface VerifyResult {
  valid: boolean;
  payload?: Record<string, unknown>;
  header?: Record<string, unknown>;
  reason?: string;
}

function base64urlDecode(str: string): Buffer {
  // Convert base64url to base64
  const base64 = str.replace(/-/g, '+').replace(/_/g, '/')
    + '=='.slice(0, (4 - str.length % 4) % 4);
  return Buffer.from(base64, 'base64');
}

export function verifyHs256(token: string, secret: string): VerifyResult {
  const parts = token.split('.');
  if (parts.length !== 3) {
    return { valid: false, reason: 'Token must have exactly 3 parts' };
  }

  const [headerB64, payloadB64, signatureB64] = parts;

  let header: Record<string, unknown>;
  try {
    header = JSON.parse(base64urlDecode(headerB64).toString('utf8'));
  } catch {
    return { valid: false, reason: 'Failed to decode header' };
  }

  if (header.alg !== 'HS256') {
    return { valid: false, reason: `Algorithm ${header.alg} not supported` };
  }

  let payload: Record<string, unknown>;
  try {
    payload = JSON.parse(base64urlDecode(payloadB64).toString('utf8'));
  } catch {
    return { valid: false, reason: 'Failed to decode payload' };
  }

  const signingInput = `${headerB64}.${payloadB64}`;
  const expectedSig = createHmac('sha256', secret).update(signingInput).digest();
  const actualSig = base64urlDecode(signatureB64);

  if (expectedSig.length !== actualSig.length) {
    return { valid: false, reason: 'Signature verification failed' };
  }

  if (!timingSafeEqual(expectedSig, actualSig)) {
    return { valid: false, reason: 'Signature verification failed' };
  }

  if (typeof payload.exp === 'number') {
    if (Math.floor(Date.now() / 1000) >= payload.exp) {
      return { valid: false, reason: 'Token has expired' };
    }
  }

  return { valid: true, header, payload };
}
